import { useState, useEffect } from 'react';
import { Form, FormField } from '../components/ppm/cms/form-builder/FormBuilderTypes';
import { getSupabase } from '../database/supabase';

const STORAGE_KEY = 'sbu_cms_builder_forms';

export const useFormData = ( isAuth ?: boolean ) => {

    const [forms, setForms] = useState<Form[]>([]);
    const [loading, setLoading] = useState(true);

    // ─────────────────────────────────────────────
    // LOAD: remote + local merge
    // ─────────────────────────────────────────────
    useEffect(() => {
        let mounted = true;

        const load = async () => {
            try {

                setLoading(true);

                // 1. LOAD REMOTE (Supabase)
                let remoteForms: Form[] = [];

                try {
                    const supabase = await getSupabase();

                    const { data, error } = await supabase
                        .from("form_definitions")
                        .select("definition, form_key");

                    if (error) throw error;

                    console.log("[useFormData][REMOTE][RAW]:", data);

                    remoteForms = (data || []).map((row: any) => {
                        const def = row.definition;
                        const form = def?.form;

                        return {
                            id: form?.id || row.form_key,
                            title: form?.title || "Untitled",
                            fields: form?.fields || [],
                            settings: def?.settings || {}
                        };
                    });

                    console.log("[useFormData][REMOTE][PARSED]:", remoteForms);

                } catch (err) {
                    console.error("[useFormData] Remote load failed:", err);
                }

                // 2. LOAD LOCAL (drafts)
                let localForms: Form[] = [];

                try {
                    const raw = localStorage.getItem(STORAGE_KEY);

                    console.log("[useFormData][LOCAL][RAW]:", raw);

                    if (raw) {
                        const parsed = JSON.parse(raw);

                        if (Array.isArray(parsed)) {
                            localForms = parsed;
                        }
                    }

                    console.log("[useFormData][LOCAL][PARSED]:", localForms);

                } catch (err) {
                    console.error("[useFormData] Local parse failed:", err);
                }

                // 3. MERGE (local overrides remote)
                const merged = remoteForms.map(remote => {
                    const local = localForms.find(l => l.id === remote.id);

                    if (local) {
                        console.log("[useFormData][MERGE][OVERRIDE]:", {
                            id: remote.id,
                            remote,
                            local
                        });
                    }

                    return local ? { ...remote, ...local } : remote;
                });

                console.log("[useFormData][MERGED]:", merged);

                // 4. INCLUDE LOCAL-ONLY (unsaved new forms)
                const localOnly = localForms.filter(
                    l => !remoteForms.some(r => r.id === l.id)
                );

                console.log("[useFormData][LOCAL_ONLY]:", localOnly);

                const finalForms = [...merged, ...localOnly];

                console.log("[useFormData][FINAL]:", finalForms);

                if (!mounted) return;

                setForms(finalForms);

            } catch (err) {
                console.error("[useFormData] Load failed:", err);
            } finally {
                if (mounted) setLoading(false);
            }
        };

        load();

        return () => {
            mounted = false;
        };
    }, []);

    // ─────────────────────────────────────────────
    // SAVE TO LOCAL (draft system)
    // ─────────────────────────────────────────────
    const saveToStorage = (updatedForms: Form[]) => {
        console.log("[useFormData][SAVE][LOCAL]:", updatedForms);
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedForms));
        setForms(updatedForms);
    };

    // ─────────────────────────────────────────────
    // CRUD (LOCAL ONLY = drafts)
    // ─────────────────────────────────────────────

    const createForm = (title: string, fields: FormField[] = []): Form => {
        const newForm: Form = {
            id: `form_${Date.now()}`,
            title: title || 'Untitled Form',
            fields
        };

        const updated = [...forms, newForm];
        saveToStorage(updated);
        return newForm;
    };

    const updateForm = (formId: string, updates: Partial<Form>) => {
        const updated = forms.map(f =>
            f.id === formId ? { ...f, ...updates } : f
        );
        saveToStorage(updated);
    };

    const deleteForm = (formId: string) => {
        const updated = forms.filter(f => f.id !== formId);
        saveToStorage(updated);
    };

    const renameForm = (formId: string, newTitle: string) => {
        updateForm(formId, { title: newTitle });
    };

    const addField = (formId: string, field: FormField) => {
        const current = forms.find(f => f.id === formId);
        if (!current) return;

        const updatedFields = [...current.fields, field];
        updateForm(formId, { fields: updatedFields });
    };

    const removeField = (formId: string, fieldId: string) => {
        const current = forms.find(f => f.id === formId);
        if (!current) return;

        const updatedFields = current.fields.filter(f => f.id !== fieldId);
        updateForm(formId, { fields: updatedFields });
    };

    return {
        forms,
        loading,
        createForm,
        updateForm,
        deleteForm,
        renameForm,
        addField,
        removeField
    };
};